import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;

public class TwoSum {

    // Approach 1: HashMap - O(n) time, O(n) space
    public static int[] twoSumHashMap(int[] nums, int target) {
        Map<Integer, Integer> map = new HashMap<>();

        for (int i = 0; i < nums.length; i++) {
            int complement = target - nums[i];

            if (map.containsKey(complement)) {
                return new int[]{map.get(complement), i};
            }

            map.put(nums[i], i);
        }

        return null; // No solution found
    }

    // Approach 2: Two Pointers (for sorted array) - O(n) time, O(1) space
    public static int[] twoSumTwoPointers(int[] numbers, int target) {
        int left = 0;
        int right = numbers.length - 1;

        while (left < right) {
            int sum = numbers[left] + numbers[right];

            if (sum == target) {
                return new int[]{left + 1, right + 1}; // 1-indexed
            } else if (sum < target) {
                left++;
            } else {
                right--;
            }
        }

        return null; // No solution found
    }

    public static void main(String[] args) {
        int[] nums = {2, 7, 11, 15};
        int target = 9;

        System.out.println("HashMap approach: " + Arrays.toString(twoSumHashMap(nums, target)));
        System.out.println("Two pointers: " + Arrays.toString(twoSumTwoPointers(nums, target)));
    }
}
